+/**
+ * Cross-tenant guard. Reject when there is no session org, OR when the claimed
+ * org_id from the args doesn't match the session org. Returns a forbidden
+ * ToolResponse on failure, `null` when the caller may proceed. Centralised so
+ * the three handlers (record_review_started, record_finding,
+ * record_review_completed) share one implementation and stay in sync.
+ */
+function requireOrgMatch(claimedOrg: string): ToolResponse | null {
+  const sessionOrg = getCurrentOrgId();
+  if (!sessionOrg || claimedOrg !== sessionOrg) {
+    return errorResponse('forbidden', `org_id must match session org (${sessionOrg || 'none'})`);
+  }
+  return null;
+}
